"""
UCCSD wavefunction object for PyCC.  Mirrors the structure of ccwfn.py.

Energy   : BCH4  (uccsd_bch4_cs.py  — 4-commutator truncation)
Residuals: BCH2  (uccsd_bch2_cs.py  — 2-commutator truncation)

All integral blocks are loaded ONCE at __init__ from ccwfn.H and stored
as attributes.  energy() and residuals() do zero disk I/O.

The t_dag convention - Ajay's SeQuant generator emits t_dag as a plain TRANSPOSE:
    t_dag_oovv = einsum('abic->icab', t_vvoo)   # correct only for real T
For complex RT amplitudes, rtcc_ucc._prep_tdag() pre-conjugates the
inputs BEFORE passing them here, so every transpose inside this file
produces the correct conjugate transpose T†.
So, do NOT add .conj() calls anywhere in this file.

Index conventions (SeQuant)
  t_vo    (nv, no)            [ai]
  t_vvoo  (nv, nv, no, no)   [abij]
  tdag_vo / tdag_vvoo : pre-conjugated inputs passed by rtcc_ucc

Interface (called by rtcc_ucc), just like normal stuff
  ucc.energy(F, ERI, t_vo, t_vvoo, tdag_vo, tdag_vvoo)    -> scalar
  ucc.residuals(F, ERI, t_vo, t_vvoo, tdag_vo, tdag_vvoo) -> (R1_vo, R2_vvoo)

Usage
  from uccwfn import make_ucc_fns
  from rtcc_ucc import rtcc_ucc

  energy_fn, residuals_fn = make_ucc_fns(ccwfn)
  rt = rtcc_ucc(ccwfn, V, energy_fn, residuals_fn, kick='z')
"""

import numpy as np
from opt_einsum import contract as ct


class UCCWfn:
    """
    UCCSD wavefunction.

    Parameters
    ----------
    ccwfn : PyCC ccwfn object
        Provides .no, .nv, .o, .v, .H.F, .H.ERI, .t1, .t2
    """

    def __init__(self, ccwfn):
        self.no = ccwfn.no
        self.nv = ccwfn.nv
        self.t1 = ccwfn.t1   # initial guess for RT propagation
        self.t2 = ccwfn.t2

        o = ccwfn.o
        v = ccwfn.v
        ERI = ccwfn.H.ERI

        # ---- Two-electron integral blocks (antisymmetrized, loaded once) ----
        self.g_oooo = ERI[o, o, o, o].copy()
        self.g_oovv = ERI[o, o, v, v].copy()
        self.g_vvoo = ERI[v, v, o, o].copy()
        self.g_ovov = ERI[o, v, o, v].copy()
        self.g_ovvo = ERI[o, v, v, o].copy()
        self.g_ovoo = ERI[o, v, o, o].copy()
        self.g_ooov = ERI[o, o, o, v].copy()
        self.g_vvvv = ERI[v, v, v, v].copy()
        self.g_vvov = ERI[v, v, o, v].copy()
        self.g_ovvv = ERI[o, v, v, v].copy()

        print(f"UCCWfn: integrals loaded  no={self.no}  nv={self.nv}")

    # ------------------------------------------------------------------
    # Field-dressed Fock blocks  (ERI blocks are field-independent)
    # ------------------------------------------------------------------
    @staticmethod
    def _fock(F, no):
        return F[:no, :no], F[no:, no:], F[:no, no:], F[no:, :no]

    # ------------------------------------------------------------------
    # BCH4 Energy
    # ------------------------------------------------------------------
    def energy(self, F, ERI, t_vo, t_vvoo, tdag_vo, tdag_vvoo):
        """UCCSD BCH4 energy (4-commutator truncation)."""
        nocc = self.no
        nvirt = self.nv   
        f_oo, f_vv, f_ov, f_vo = self._fock(F, nocc)

        E = 0.0


        E = 0.0
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        g_vvov = self.g_vvov
        I2_oovv += ct('abic,cd->idab', g_vvov, t_vo)
        I_oooovvvv += ct('iabc,defg->iafgbcde', I2_oovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        I_oovv += ct('iabcdefg,iagf->bcde', I_oooovvvv, t_dag_oovv)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -4/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv += ct('ia,bcdi->adbc', f_oo, t_vvoo)
        I_oooovvvv += ct('iabc,defg->iafgbcde', I2_oovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        I_oovv += ct('iabcdefg,iagf->bcde', I_oooovvvv, t_dag_oovv)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 2/3 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ovvvvv = np.zeros((nocc, nvirt, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        g_vvvv = self.g_vvvv
        I_ovvvvv += ct('abcd,ei->iabcde', g_vvvv, t_vo)
        I_ooovvv += ct('iabcde,cdfg->ifgabe', I_ovvvvv, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,bc->iade', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -2 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv += ct('ia,bcdi->adbc', f_oo, t_vvoo)
        I_oooovvvv += ct('iabc,defg->iafgbcde', I2_oovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        I_oovv += ct('iabcdefg,ibfd->aceg', I_oooovvvv, t_dag_oovv)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -4/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        g_ovov = self.g_ovov
        I_ov += ct('iabc,ci->ba', g_ovov, t_vo)
        I_ooovvv += ct('ia,bcde->ideabc', I_ov, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,ie->abcd', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 8/3 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_oooovv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        g_oooo = self.g_oooo
        I_oooovv += ct('iabc,deif->abcfde', g_oooo, t_vvoo)
        I_oooovvvv += ct('iabcde,fgih->abchdefg', I_oooovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        I_oovv += ct('iabcdefg,iagd->bcef', I_oooovvvv, t_dag_oovv)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 8/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        g_oovv = self.g_oovv
        I2_oovv += ct('iabc,bdie->aecd', g_oovv, t_vvoo)
        I_oovv += ct('iabc,bdie->aecd', I2_oovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -8/3 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        g_vvoo = self.g_vvoo
        I_oooovvvv += ct('abic,defg->icfgabde', g_vvoo, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_ooovvv += ct('iabcdefg,ig->abcdef', I_oooovvvv, t_dag_ov)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,be->iacd', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv += ct('ai,bc->icab', f_vo, t_vo)
        I_ooovvv += ct('iabc,de->iaebcd', I2_oovv, t_vo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,bc->iade', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -3/2 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        g_vvoo = self.g_vvoo
        I_oooovvvv += ct('abic,defg->icfgabde', g_vvoo, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_ooovvv += ct('iabcdefg,ig->abcdef', I_oooovvvv, t_dag_ov)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,bc->iade', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 3 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        I_ov += ct('ab,bi->ia', f_vv, t_vo)
        I_ooovvv += ct('ia,bcde->ideabc', I_ov, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,be->iacd', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 4/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_oooovv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        g_ovvo = self.g_ovvo
        I_oooovv += ct('iabc,bdef->icfead', g_ovvo, t_vvoo)
        I_oooovvvv += ct('iabcde,fgih->abchdefg', I_oooovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        I_oovv += ct('iabcdefg,iadg->bcef', I_oooovvvv, t_dag_oovv)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -8/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oooovvvv = np.zeros((nocc, nocc, nocc, nocc, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        g_ovvo = self.g_ovvo
        I2_oovv += ct('iabc,bdie->cead', g_ovvo, t_vvoo)
        I_oooovvvv += ct('iabc,defg->iafgbcde', I2_oovv, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        I_oovv += ct('iabcdefg,iaeg->bcdf', I_oooovvvv, t_dag_oovv)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 16/3 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ooov = np.zeros((nocc, nocc, nocc, nvirt), dtype=complex, order='F')
        I_ooov += ct('ia,bc->iacb', f_oo, t_vo)
        I_ooovvv += ct('iabc,defi->abfcde', I_ooov, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,ad->ibce', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -2/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        g_ovvo = self.g_ovvo
        I_ov += ct('iabc,bi->ca', g_ovvo, t_vo)
        I_ooovvv += ct('ia,bcde->ideabc', I_ov, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,ie->abcd', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 8/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_oo = np.zeros((nocc, nocc), dtype=complex, order='F')
        g_oovv = self.g_oovv
        I_oo += ct('iabc,bcda->id', g_oovv, t_vvoo)
        I_oovv += ct('ia,bcdi->dabc', I_oo, t_vvoo)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += 8/3 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        g_ooov = self.g_ooov
        I_ov += ct('iabc,cdai->bd', g_ooov, t_vvoo)
        I_ooovvv += ct('ia,bcde->ideabc', I_ov, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,be->iacd', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -8/3 * ct('iabc,iabc->', I_oovv, t_dag_oovv)
        I_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I2_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        g_ovvo = self.g_ovvo
        I2_ov += ct('iabc,bi->ca', g_ovvo, t_vo)
        I_oovv += ct('ia,bc->icab', I2_ov, t_vo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_ov += ct('iabc,ic->ab', I_oovv, t_dag_ov)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        E += -8/3 * ct('ia,ia->', I_ov, t_dag_ov)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I2_oovv += ct('ai,bc->icab', f_vo, t_vo)
        I_ooovvv += ct('iabc,de->iaebcd', I2_oovv, t_vo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
        I_oovv += ct('iabcde,ie->abcd', I_ooovvv, t_dag_ov)
        t_dag_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        t_dag_oovv += ct('abic->icab', tdag_vvoo)
        E += -3/2 * ct('iabc,iacb->', I_oovv, t_dag_oovv)
        I_oovv = np.zeros((nocc, nocc, nvirt, nvirt), dtype=complex, order='F')
        I_ooovvv = np.zeros((nocc, nocc, nocc, nvirt, nvirt, nvirt), dtype=complex, order='F')
        I_ovvvvv = np.zeros((nocc, nvirt, nvirt, nvirt, nvirt, nvirt), dtype=complex, order='F')
        g_vvvv = self.g_vvvv
        I_ovvvvv += ct('abcd,ei->iabcde', g_vvvv, t_vo)
        I_ooovvv += ct('iabcde,cdfg->ifgabe', I_ovvvvv, t_vvoo)
        t_dag_ov = np.zeros((nocc, nvirt), dtype=complex, order='F')
        t_dag_ov += ct('ai->ia', tdag_vo)
