# ------------------------------------------------------------------
# Convenience builder
# ------------------------------------------------------------------
def make_ucc_fns(ccwfn):
    """
    Build energy and residuals callables from a PyCC ccwfn object.
    Integral blocks are loaded once inside UCCWfn.__init__().

    Returns
    -------
    energy_fn, residuals_fn
        Pass directly to rtcc_ucc().

    Example
    -------
        from uccwfn import make_ucc_fns
        from rtcc_ucc import rtcc_ucc

        energy_fn, residuals_fn = make_ucc_fns(cc)
        rt = rtcc_ucc(cc, V, energy_fn, residuals_fn, kick='z')
    """
    ucc = UCCWfn(ccwfn)
    return ucc.energy, ucc.residuals
